79	    S_Axi_AwBurst : in  std_logic_vector(1 downto 0);
80	    S_Axi_AwLock  : in  std_logic;
81	    S_Axi_AwCache : in  std_logic_vector(3 downto 0);
82	    S_Axi_AwProt  : in  std_logic_vector(2 downto 0);
83	    S_Axi_AwValid : in  std_logic;
84	    S_Axi_AwReady : out std_logic;
85	    S_Axi_WData   : in  std_logic_vector(31 downto 0);
86	    S_Axi_WStrb   : in  std_logic_vector(3 downto 0);
87	    S_Axi_WLast   : in  std_logic;
88	    S_Axi_WValid  : in  std_logic;
89	    S_Axi_WReady  : out std_logic;
90	    S_Axi_BId     : out std_logic_vector(AxiSlaveIdWidth_g - 1 downto 0);
91	    S_Axi_BResp   : out std_logic_vector(1 downto 0);
92	    S_Axi_BValid  : out std_logic;
93	    S_Axi_BReady  : in  std_logic;
94	    -- AXI Master Interface for Memory Access
95	    M_Axi_Aclk    : in  std_logic;
96	    M_Axi_Aresetn : in  std_logic;
97	    M_Axi_AwAddr  : out std_logic_vector(31 downto 0);
