23	------------------------------------------------------------------------------
24	-- Entity Declaration
25	------------------------------------------------------------------------------
26	-- $$ testcases=single_frame,multi_frame,timeout,ts_overflow,trig_in_posttrig,always_trig,backpressure,modes $$
27	-- $$ processes=stream,daq $$
28	-- $$ tbpkg=work.psi_tb_txt_util $$
29	entity psi_ms_daq_input is
30	  generic(
31	    StreamWidth_g       : positive range 8 to 64    := 16; -- Must be 8, 16, 32 or 64						$$ export=true $$
32	    StreamBuffer_g      : positive range 1 to 65535 := 1024; -- Buffer depth in QWORDs						$$ constant=32 $$
33	    StreamTimeout_g     : real                      := 1.0e-3; -- Timeout in seconds							$$ constant=10.0e-6 $$
34	    StreamClkFreq_g     : real                      := 125.0e6; -- Input clock frequency in Hz					$$ constant=125.0e6 $$
35	    StreamTsFifoDepth_g : positive                  := 16; -- Timestamp FIFO depth							$$ constant=3 $$
36	    StreamUseTs_g       : boolean                   := true; -- Enable/Disable the timestamp acquisition		$$ constant=true $$
37	    IntDataWidth_g      : positive                  := 64
38	  );
39	  port(
40	    -- Data Stream Input
41	    Str_Clk      : in  std_logic;       -- $$ type=clk; freq=125e6; proc=stream $$
42	    Str_Vld      : in  std_logic;       -- $$ proc=stream $$
43	    Str_Rdy      : out std_logic;       -- $$ proc=stream $$
44	    Str_Data     : in  std_logic_vector(StreamWidth_g - 1 downto 0); -- $$ proc=stream $$
45	    Str_Trig     : in  std_logic;       -- $$ proc=stream $$
46	    Str_Ts       : in  std_logic_vector(63 downto 0); -- $$ proc=stream $$
47	
48	    -- Configuration Signals
49	    ClkReg       : in  std_logic;
50	    RstReg       : in  std_logic;
51	    PostTrigSpls : in  std_logic_vector(31 downto 0); -- $$ proc=daq $$
52	    Mode         : in  RecMode_t;       -- $$ proc=daq $$
53	    Arm          : in  std_logic;       -- $$ proc=stream $$
54	    IsArmed      : out std_logic;       -- $$ proc=stream $$
55	    IsRecording  : out std_logic;       -- $$ proc=stream $$
56	    ToDisable    : in  std_logic;       -- $$ proc=stream $$
57	    FrameTo      : in  std_logic;       -- $$ proc=stream $$
58	
59	    -- DAQ control signals
60	    ClkMem       : in  std_logic;       -- $$ type=clk; freq=200e6; proc=daq,stream $$
61	    RstMem       : in  std_logic;       -- $$ type=rst; clk=Clk $$
62	
63	    -- DAQ logic Connections
64	    Daq_Vld      : out std_logic;       -- $$ proc=daq $$
65	    Daq_Rdy      : in  std_logic;       -- $$ proc=daq $$
66	    Daq_Data     : out Input2Daq_Data_t(Data(IntDataWidth_g-1 downto 0), Bytes(log2ceil(IntDataWidth_g/8) downto 0)); -- $$ proc=daq $$
67	    Daq_Level    : out std_logic_vector(15 downto 0); -- $$ proc=daq $$
68	    Daq_HasLast  : out std_logic;       -- $$ proc=daq $$
69	
70	    -- Timestamp connections
71	    Ts_Vld       : out std_logic;       -- $$ proc=daq $$
72	    Ts_Rdy       : in  std_logic;       -- $$ proc=daq $$
73	    Ts_Data      : out std_logic_vector(63 downto 0) -- $$ proc=daq $$
74	  );
75	end entity;
