77	------------------------------------------------------------------------------
78	-- Architecture Declaration
79	------------------------------------------------------------------------------
80	architecture rtl of psi_ms_daq_input is
81	
82	  -- Use distributed RAM for small Timstamp FIFOs (< 64 entries)
83	  constant TsFifoStyle_c : string := choose(StreamTsFifoDepth_g <= 64, "distributed", "block");
84	
85	  -- Constants
86	  constant TimeoutLimit_c  : integer  := integer(StreamClkFreq_g * StreamTimeout_g) - 1;
87	  constant WconvFactor_c   : positive := IntDataWidth_g / StreamWidth_g;
88	  constant BytesWidth_c    : positive := log2ceil(IntDataWidth_g/8) + 1;
89	  constant TlastCntWidth_c : positive := log2ceil(StreamBuffer_g) + 1;
90	  constant DataFifoWidth_c : positive := IntDataWidth_g + BytesWidth_c + 2;
91	
92	  -- Two process method
93	  type two_process_r is record
94	    ModeReg        : RecMode_t;
95	    ArmReg         : std_logic;
96	    DataSftReg     : std_logic_vector(IntDataWidth_g-1 downto 0);
97	    WordCnt        : unsigned(log2ceil(WconvFactor_c) downto 0);
98	    DataFifoBytes  : unsigned(BytesWidth_c-1 downto 0);
99	    TrigLatch      : std_logic;
100	    DataFifoVld    : std_logic;
101	    DataFifoIsTo   : std_logic;
102	    DataFifoIsTrig : std_logic;
103	    TimeoutCnt     : integer range 0 to TimeoutLimit_c;
104	    Timeout        : std_logic;
105	    PostTrigCnt    : unsigned(31 downto 0);
106	    TLastCnt       : std_logic_vector(TlastCntWidth_c - 1 downto 0);
107	    TsLatch        : std_logic_vector(63 downto 0);
108	    TsOverflow     : std_logic;
109	    HasTlastSync   : std_logic_vector(0 to 1);
110	    IsArmed        : std_logic;
111	    RecEna         : std_logic;
112	    FrameInProgr   : std_logic;
113	  end record;
114	  signal r, r_next : two_process_r;
115	
116	  -- General Instantiation signals
117	  signal Str_Rst : std_logic;
118	
119	  -- Data FIFO signals
120	  signal DataFifo_InRdy   : std_logic;
121	  signal DataFifo_InData  : std_logic_vector(DataFifoWidth_c-1 downto 0);
122	  signal DataFifo_OutData : std_logic_vector(DataFifoWidth_c-1 downto 0);
123	  signal DataFifo_PlData  : std_logic_vector(DataFifoWidth_c-1 downto 0);
124	  signal DataFifo_PlVld   : std_logic;
125	  signal DataFifo_PlRdy   : std_logic;
126	  signal DataFifo_Level   : std_logic_vector(log2ceil(StreamBuffer_g) downto 0);
127	  signal DataPl_Level     : unsigned(1 downto 0);
128	
129	  -- Internally reused signals
130	  signal Daq_Data_I    : Input2Daq_Data_t(Data(IntDataWidth_g-1 downto 0), Bytes(BytesWidth_c-1 downto 0));
131	  signal Daq_Vld_I     : std_logic;
132	  signal Daq_HasLast_I : std_logic;
133	  signal Ts_Vld_I      : std_logic;
134	
135	  -- Signal output side TLAST handling
136	  signal OutTlastCnt : std_logic_vector(TlastCntWidth_c - 1 downto 0);
137	  signal InTlastCnt  : std_logic_vector(TlastCntWidth_c - 1 downto 0);
138	
139	  -- Timestamp FIFO signals
140	  signal TsFifo_InRdy   : std_logic;
141	  signal TsFifo_InVld   : std_logic;
142	  signal TsFifo_RdData  : std_logic_vector(63 downto 0);
143	  signal TsFifo_AlmFull : std_logic;
144	  signal TsFifo_Empty   : std_logic;
145	
146	  -- Clock Crossing Signals
147	  signal PostTrigSpls_Sync : std_logic_vector(PostTrigSpls'range);
148	  signal Mode_Sync         : RecMode_t;
149	  signal Arm_Sync          : std_logic;
150	  signal RstReg_Sync       : std_logic;
151	  signal RstAcq_Sync       : std_logic;
152	  signal ToDisable_Sync    : std_logic;
153	  signal FrameTo_Sync      : std_logic;
154	
155	begin
156	  --------------------------------------------
157	  -- Combinatorial Process
158	  --------------------------------------------
159	  p_comb : process(r, Str_Vld, Str_Data, Str_Trig, Str_Ts, PostTrigSpls_Sync, Daq_Rdy, Ts_Rdy, Mode_Sync, Arm_Sync, DataFifo_InRdy, DataFifo_InData, DataFifo_OutData, Daq_Vld_I, Daq_Data_I, Daq_HasLast_I, Ts_Vld_I, OutTlastCnt, TsFifo_AlmFull, TsFifo_Empty, InTlastCnt, TsFifo_InRdy, TsFifo_RdData)
160	    variable v               : two_process_r;
161	    variable ProcessSample_v : boolean;
162	    variable TriggerSample_v : boolean;
163	    variable AddSamples_v    : integer range 0 to 1;
164	    variable TrigMasked_v    : std_logic;
165	  begin
166	    -- *** Hold variables stable ***
167	    v := r;
168	
169	    -- *** Simplification Variables ***
170	    ProcessSample_v := (DataFifo_InRdy = '1') and (Str_Vld = '1');
171	
172	    -- *** Input Logic Stage ***
173	    -- Default values
174	    v.DataFifoIsTo   := '0';
175	    v.DataFifoIsTrig := '0';
176	    v.ModeReg        := Mode_Sync;
177	    v.ArmReg         := Arm_Sync;
178	
179	    -- Masking trigger according to recording mode
180	    case r.ModeReg is
181	      when RecMode_Continuous_c =>
182	        TrigMasked_v := Str_Trig;
183	      when RecMode_TriggerMask_c |
184				     RecMode_SingleShot_c =>
185	        TrigMasked_v := Str_Trig and r.IsArmed;
186	      when RecMode_ManuelMode_c =>
187	        TrigMasked_v := r.ArmReg;
188	      when others => null;
189	    end case;
190	
191	    -- Keep FifoVld high until data is written
192	    v.DataFifoVld := r.DataFifoVld and not DataFifo_InRdy;
193	
194	    -- Trigger Latching
195	    if ProcessSample_v then
196	      v.TrigLatch := '0';
197	    else
198	      v.TrigLatch := r.TrigLatch or TrigMasked_v;
199	    end if;
200	
201	    -- Detect timestamp FIFO overflows
202	    if StreamUseTs_g then
203	      v.HasTlastSync(0) := Daq_HasLast_I;
204	      v.HasTlastSync(1) := r.HasTlastSync(0);
205	      if (TsFifo_AlmFull = '1') and (r.DataFifoVld = '1') then
206	        v.TsOverflow := '1';
207	      elsif (r.HasTlastSync(1) = '0') and (TsFifo_Empty = '1') then
208	        v.TsOverflow := '0';
209	      end if;
210	    end if;
211	
212	    -- Timestamp latching
213	    if StreamUseTs_g then
214	      if (TrigMasked_v = '1') and (unsigned(r.PostTrigCnt) = 0) then
215	        if (TsFifo_AlmFull = '1') or (r.TsOverflow = '1') then
216	          v.TsLatch := (others => '1');
217	        else
218	          v.TsLatch := Str_Ts;
219	        end if;
220	      end if;
221	    end if;
222	
223	    -- Trigger handling and post trigger counter
224	    if ProcessSample_v and r.RecEna = '1' then
225	      if r.PostTrigCnt /= 0 then
226	        v.PostTrigCnt := r.PostTrigCnt - 1;
227	        if r.PostTrigCnt = 1 then
228	          v.DataFifoIsTrig := '1';
229	          v.DataFifoVld    := r.DataFifoVld or r.RecEna;
230	          v.RecEna         := '0';      -- stop recording after frame
231	        end if;
232	      elsif (r.TrigLatch = '1') or (TrigMasked_v = '1') then
233	        -- Handle incoming trigger sample
234	        if unsigned(PostTrigSpls_Sync) = 0 then
235	          v.DataFifoIsTrig := '1';
236	          v.DataFifoVld    := r.DataFifoVld or r.RecEna;
237	          v.RecEna         := '0';      -- stop recording after frame
238	        else
239	          v.PostTrigCnt := unsigned(PostTrigSpls_Sync);
240	        end if;
241	      end if;
242	    end if;
243	
244	    -- Frame in progress
245	    if Str_Vld = '1' then
246	      if Str_Trig = '1' then
247	        v.FrameInProgr := '0';
248	      else
249	        v.FrameInProgr := '1';
250	      end if;
251	    end if;
252	
253	    -- Detect Timeout
254	    if Str_Vld = '1' or ToDisable_Sync = '1' or (FrameTo_Sync = '1' or r.FrameInProgr = '0') then
255	      v.TimeoutCnt := 0;
256	    else
257	      if r.TimeoutCnt = TimeoutLimit_c then
258	        v.TimeoutCnt := 0;
259	        v.Timeout    := '1';
260	      else
261	        v.TimeoutCnt := r.TimeoutCnt + 1;
262	      end if;
263	    end if;
264	
265	    -- TLast counter
266	    if (r.DataFifoVld = '1') and ((r.DataFifoIsTo = '1') or (r.DataFifoIsTrig = '1')) then
267	      v.TLastCnt := std_logic_vector(unsigned(r.TLastCnt) + 1);
268	    end if;
269	
270	    -- Write because timeout occured (only if data is stuck in conversion)
271	    if r.Timeout = '1' then
272	      v.DataFifoVld  := r.DataFifoVld or r.RecEna;
273	      v.DataFifoIsTo := '1';
274	      v.Timeout      := '0';            -- reser timeout after data was flushed to the FIFO
275	    end if;
276	    -- Process input data
277	    if ProcessSample_v and r.RecEna = '1' then
278	      v.WordCnt                                                                                                  := r.WordCnt + 1;
279	      -- Write because full word is ready
280	      if r.WordCnt = WconvFactor_c - 1 then
281	        v.DataFifoVld := r.DataFifoVld or r.RecEna;
282	      end if;
283	      v.DataSftReg((to_integer(r.WordCnt) + 1) * StreamWidth_g - 1 downto to_integer(r.WordCnt) * StreamWidth_g) := Str_Data;
284	    end if;
285	    -- Reset counter if data is being written to FIFO
286	    if v.DataFifoVld = '1' then
287	      v.WordCnt := (others => '0');
288	    end if;
289	
290	    -- Convert word counter to byte counter
291	    v.DataFifoBytes := (others => '0');
292	    if r.Timeout = '1' then
293	      AddSamples_v := 0;
294	    else
295	      AddSamples_v := 1;
296	    end if;
297	    case StreamWidth_g is
298	      when 8      => v.DataFifoBytes := r.WordCnt + AddSamples_v;
299	      when 16     => v.DataFifoBytes := (r.WordCnt + AddSamples_v) & "0";
300	      when 32     => v.DataFifoBytes := (r.WordCnt + AddSamples_v) & "00";
301	      when 64     => v.DataFifoBytes := (r.WordCnt + AddSamples_v) & "000";
302	      when others => null;
303	    end case;
304	
305	    -- Handle Arming Logic
306	    if (r.ModeReg /= Mode_Sync) or (r.ModeReg = RecMode_Continuous_c) or (r.ModeReg = RecMode_ManuelMode_c) then -- reset on mode change!
307	      v.IsArmed := '0';
308	    elsif r.ArmReg = '1' then
309	      v.IsArmed := '1';
310	    elsif TrigMasked_v = '1' then
311	      v.IsArmed := '0';
312	    end if;
313	
314	    -- Enable Recording Logic
315	    case r.ModeReg is
316	      when RecMode_Continuous_c |
317					 RecMode_TriggerMask_c =>
318	        -- always enabled
319	        v.RecEna := '1';
320	      when RecMode_SingleShot_c |
321					 RecMode_ManuelMode_c =>
322	        -- enable on arming (disable happens after recording)
323	        if v.ArmReg = '1' then
324	          v.RecEna := '1';
325	        end if;
326	      when others => null;
327	    end case;
328	    if r.ModeReg /= Mode_Sync then
329	      v.RecEna := '0';
330	    end if;
331	
332	    -- *** Assign to signal ***
333	    r_next <= v;
334	
335	  end process;
336	
337	  --------------------------------------------
338	  -- Sequential Process
339	  --------------------------------------------
340	  p_seq : process(Str_Clk)
341	  begin
342	    if rising_edge(Str_Clk) then
343	      r <= r_next;
344	      if Str_Rst = '1' then
345	        r.WordCnt      <= (others => '0');
346	        r.TrigLatch    <= '0';
347	        r.TimeoutCnt   <= 0;
348	        r.Timeout      <= '0';
349	        r.PostTrigCnt  <= (others => '0');
350	        r.TLastCnt     <= (others => '0');
351	        r.TsOverflow   <= '0';
352	        r.HasTlastSync <= (others => '0');
353	        r.IsArmed      <= '0';
354	        r.RecEna       <= '0';
355	        r.ArmReg       <= '0';
356	        r.FrameInProgr <= '0';
357	      end if;
358	    end if;
359	  end process;
360	
361	  --------------------------------------------
362	  -- Output Side TLAST handling
363	  --------------------------------------------
364	  p_outlast : process(ClkMem)
365	    variable PlLevel_v : unsigned(DataPl_Level'range);
366	  begin
367	    if rising_edge(ClkMem) then
368	      -- Default Value
369	      Daq_HasLast_I <= '0';
370	
371	      -- Count TLAST read from output buffer
372	      if (Daq_Vld_I = '1') and (Daq_Rdy = '1') and (Daq_Data_I.Last = '1') then
373	        OutTlastCnt <= std_logic_vector(unsigned(OutTlastCnt) + 1);
374	      end if;
375	
376	      -- Detect if there are TLASTs in the buffer
377	      if OutTlastCnt /= InTlastCnt then
378	        Daq_HasLast_I <= '1';
379	      end if;
380	
381	      -- Level Calculation (add samples in PL stage)
382	      PlLevel_v    := DataPl_Level;
383	      if DataFifo_PlRdy = '1' and DataFifo_PlVld = '1' then
384	        PlLevel_v := PlLevel_v + 1;
385	      end if;
386	      if Daq_Vld_I = '1' and Daq_Rdy = '1' then
387	        PlLevel_v := PlLevel_v - 1;
388	      end if;
389	      DataPl_Level <= PlLevel_v;
390	      -- We calculate the level one cycle late but this does not play any role (the DAQ FSM only runs after data is transferred)
391	      Daq_Level    <= std_logic_vector(resize(unsigned(DataFifo_Level), Daq_Level'length) + DataPl_Level);
392	
393	      -- Reset
394	      if RstMem = '1' then
395	        OutTlastCnt  <= (others => '0');
396	        Daq_Level    <= (others => '0');
397	        DataPl_Level <= (others => '0');
398	      end if;
399	
400	    end if;
401	  end process;
402	  Daq_HasLast <= Daq_HasLast_I;
403	
404	  --------------------------------------------
405	  -- Component Instantiation
406	  --------------------------------------------
407	  -- *** Register Interface clock crossings ***
408	  i_cc_reg_status : entity work.psi_common_status_cc
409	    generic map(
410	      width_g => 36
411	    )
412	    port map(
413	      a_clk_i               => ClkReg,
414	      a_rst_i               => '0',
415	      a_dat_i(31 downto 0)  => PostTrigSpls,
416	      a_dat_i(33 downto 32) => Mode,
417	      a_dat_i(34)           => ToDisable,
418	      a_dat_i(35)           => FrameTo,
419	      b_clk_i               => Str_Clk,
420	      b_rst_i               => Str_Rst,
421	      b_dat_o(31 downto 0)  => PostTrigSpls_Sync,
422	      b_dat_o(33 downto 32) => Mode_Sync,
423	      b_dat_o(34)           => ToDisable_Sync,
424	      b_dat_o(35)           => FrameTo_Sync
425	    );
426	
427	  i_cc_status : entity work.psi_common_bit_cc
428	    generic map(
429	      width_g => 2
430	    )
431	    port map(
432	      dat_i(0) => r.IsArmed,
433	      dat_i(1) => r.RecEna,
434	      clk_i    => ClkReg,
435	      dat_o(0) => IsArmed,
436	      dat_o(1) => IsRecording
437	    );
438	
439	  i_cc_reg_pulse : entity work.psi_common_pulse_cc
440	    generic map(
441	      num_pulses_g => 1
442	    )
443	    port map(
444	      a_clk_i    => ClkReg,
445	      a_rst_i    => '0',
446	      a_dat_i(0) => Arm,
447	      b_clk_i    => Str_Clk,
448	      b_rst_i    => Str_Rst,
449	      b_rst_o    => open,
450	      b_dat_o(0) => Arm_Sync
451	    );
452	
453	  -- *** Reset Handling ***
454	  icc_reg_rst : entity work.psi_common_bit_cc
455	    generic map(
456	      width_g => 1
457	    )
458	    port map(
459	      dat_i(0) => RstReg,
460	      clk_i    => Str_Clk,
461	      dat_o(0) => RstReg_Sync
462	    );
463	
464	  icc_mem_rst : entity work.psi_common_bit_cc
465	    generic map(
466	      width_g => 1
467	    )
468	    port map(
469	      dat_i(0) => RstMem,
470	      clk_i    => Str_Clk,
471	      dat_o(0) => RstAcq_Sync
472	    );
473	  Str_Rst <= RstReg_Sync or RstAcq_Sync;
474	
475	  -- *** Acquisition Clock Crossing ***
476	  -- Clock crossing for reset and TLAST counter
477	  i_cc : entity work.psi_common_status_cc
478	    generic map(
479	      width_g => TlastCntWidth_c
480	    )
481	    port map(
482	      a_clk_i => Str_Clk,
483	      a_rst_i => Str_Rst,
484	      a_rst_o => open,
485	      a_dat_i => r.TLastCnt,
486	      b_clk_i => ClkMem,
487	      b_rst_i => '0',
488	      b_dat_o => InTlastCnt
489	    );
490	
491	  -- Data FIFO
492	  DataFifo_InData(IntDataWidth_g-1 downto 0)  <= r.DataSftReg;
493	  DataFifo_InData(IntDataWidth_g+BytesWidth_c-1 downto IntDataWidth_g) <= std_logic_vector(r.DataFifoBytes);
494	  DataFifo_InData(DataFifo_InData'high - 1) <= r.DataFifoIsTo;
495	  DataFifo_InData(DataFifo_InData'high)     <= r.DataFifoIsTrig;
496	
497	  i_dfifo : entity work.psi_common_async_fifo
498	    generic map(
499	      width_g     => DataFifoWidth_c,
500	      depth_g     => StreamBuffer_g,
501	      afull_on_g  => false,
502	      aempty_on_g => false
503	    )
504	    port map(
505	      in_clk_i  => Str_Clk,
506	      in_rst_i  => Str_Rst,
507	      out_clk_i => ClkMem,
508	      out_rst_i => '0',
509	      in_dat_i  => DataFifo_InData,
510	      in_vld_i  => r.DataFifoVld,
511	      in_rdy_o  => DataFifo_InRdy,
512	      out_dat_o => DataFifo_PlData,
513	      out_vld_o => DataFifo_PlVld,
514	      out_rdy_i => DataFifo_PlRdy,
515	      out_lvl_o => DataFifo_Level
516	    );
517	
518	  -- An additional pipeline stage after the FIFO is required for timing reasons
519	  i_dplstage : entity work.psi_common_pl_stage
520	    generic map(
521	      width_g   => DataFifoWidth_c,
522	      use_rdy_g => true
523	    )
524	    port map(
525	      clk_i => ClkMem,
526	      rst_i => RstMem,
527	      vld_i => DataFifo_PlVld,
528	      rdy_o => DataFifo_PlRdy,
529	      dat_i => DataFifo_PlData,
530	      vld_o => Daq_Vld_I,
531	      rdy_i => Daq_Rdy,
532	      dat_o => DataFifo_OutData
533	    );
534	  Str_Rdy <= DataFifo_InRdy;
535	
536	  Daq_Data_I.Data   <= DataFifo_OutData(IntDataWidth_g-1 downto 0);
537	  Daq_Data_I.Bytes  <= DataFifo_OutData(IntDataWidth_g+BytesWidth_c-1 downto IntDataWidth_g);
538	  Daq_Data_I.IsTo   <= DataFifo_OutData(DataFifo_OutData'high-1);
539	  Daq_Data_I.IsTrig <= DataFifo_OutData(DataFifo_OutData'high);
540	  Daq_Data_I.Last   <= Daq_Data_I.IsTo or Daq_Data_I.IsTrig;
541	  Daq_Data          <= Daq_Data_I;
542	  Daq_Vld           <= Daq_Vld_I;
543	
544	  -- Timestamp FIFO
545	  g_timestamp : if StreamUseTs_g generate
546	    TsFifo_InVld <= r.DataFifoVld and r.DataFifoIsTrig;
547	
548	    i_tsfifo : entity work.psi_common_async_fifo
549	      generic map(
550	        width_g     => 64,
551	        depth_g     => StreamTsFifoDepth_g,
552	        afull_on_g  => True,
553	        afull_lvl_g => StreamTsFifoDepth_g - 1,
554	        aempty_on_g => false,
555	        ram_style_g => TsFifoStyle_c
556	      )
557	      port map(
558	        in_clk_i   => Str_Clk,
559	        in_rst_i   => Str_Rst,
560	        out_clk_i  => ClkMem,
561	        out_rst_i  => '0',
562	        in_dat_i   => r.TsLatch,
563	        in_vld_i   => TsFifo_InVld,
564	        in_rdy_o   => TsFifo_InRdy,
565	        in_afull_o => TsFifo_AlmFull,
566	        in_empty_o => TsFifo_Empty,
567	        out_dat_o  => TsFifo_RdData,
568	        out_vld_o  => Ts_Vld_I,
569	        out_rdy_i  => Ts_Rdy
570	      );
571	    Ts_Vld  <= Ts_Vld_I;
572	    -- Replace data by 0xFF... if no valid timestamp is available
573	    Ts_Data <= (others => '1') when Ts_Vld_I = '0' else TsFifo_RdData;
574	  end generate;
575	
576	  g_ntimestamp : if not StreamUseTs_g generate
577	    Ts_Vld  <= '0';
578	    Ts_Data <= (others => '1');
579	  end generate;
580	
581	  --------------------------------------------
582	  -- Assertions
583	  --------------------------------------------
584	  p_assert : process(ClkMem)
585	  begin
586	    if rising_edge(ClkMem) then
587	      assert StreamWidth_g = 8 or StreamWidth_g = 16 or StreamWidth_g = 32 or StreamWidth_g = 64 report "###ERROR###: psi_ms_daq_input: StreamWidth_g must be 8, 16, 32 or 64" severity error;
588	    end if;
589	  end process;
590	
591	end;
592

