7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This component calculates a binary division of two fixed point values.
11	
12	------------------------------------------------------------------------------
13	-- Libraries
14	------------------------------------------------------------------------------
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.numeric_std.all;
18	
19	library work;
20	use work.psi_common_math_pkg.all;
21	use work.psi_common_logic_pkg.all;
22	use work.psi_common_array_pkg.all;
23	use work.psi_ms_daq_pkg.all;
24	
25	------------------------------------------------------------------------------
26	-- Entity Declaration
27	------------------------------------------------------------------------------
28	-- $$ testcases=aligned,unaligned,no_data_read,input_empty,empty_timeout,cmd_full,data_full,errors $$
29	-- $$ processes=control,input,mem_cmd,mem_dat $$
30	-- $$ tbpkg=work.psi_tb_txt_util,work.psi_tb_compare_pkg,work.psi_tb_activity_pkg $$
31	entity psi_ms_daq_daq_dma is
32	  generic(
33	    Streams_g      : positive range 1 to 32 := 4; -- $$ constant=4 $$
34	    IntDataWidth_g : positive               := 64 -- $$ constant=64 $$
35	  );
36	  port(
37	    -- Control signals
38	    Clk            : in  std_logic;     -- $$ type=clk; freq=200e6; proc=control,input,mem_dat,mem_cmd $$				
39	    Rst            : in  std_logic;     -- $$ type=rst; clk=Clk; proc=control $$
40	
41	    -- DAQ Statemachione Connections
42	    DaqSm_Cmd      : in  DaqSm2DaqDma_Cmd_t; -- $$ proc=control $$					
43	    DaqSm_Cmd_Vld  : in  std_logic;     -- $$ proc=control $$	
44	    DaqSm_Resp     : out DaqDma2DaqSm_Resp_t; -- $$ proc=control $$	
45	    DaqSm_Resp_Vld : out std_logic;     -- $$ proc=control $$	
46	    DaqSm_Resp_Rdy : in  std_logic;     -- $$ proc=control $$	
47	    DaqSm_HasLast  : out std_logic_vector(Streams_g - 1 downto 0); -- $$ proc=control $$
48	
49	    -- Input handling connections
50	    Inp_Vld        : in  std_logic_vector(Streams_g - 1 downto 0); -- $$ proc=input $$	
51	    Inp_Rdy        : out std_logic_vector(Streams_g - 1 downto 0); -- $$ proc=input $$	
52	    Inp_Data       : in  Input2Daq_Data_a(Streams_g - 1 downto 0)(Data(IntDataWidth_g-1 downto 0), Bytes(log2ceil(IntDataWidth_g/8) downto 0)); -- $$ proc=input $$
53	
54	    -- Memory interface connections
55	    Mem_CmdAddr    : out std_logic_vector(31 downto 0); -- $$ proc=mem_cmd $$	
56	    Mem_CmdSize    : out std_logic_vector(31 downto 0); -- $$ proc=mem_cmd $$	
57	    Mem_CmdVld     : out std_logic;     -- $$ proc=mem_cmd $$	
58	    Mem_CmdRdy     : in  std_logic;     -- $$ proc=mem_cmd $$	
59	    Mem_DatData    : out std_logic_vector(IntDataWidth_g-1 downto 0); -- $$ proc=mem_dat $$
60	    Mem_DatVld     : out std_logic;     -- $$ proc=mem_dat $$	
61	    Mem_DatRdy     : in  std_logic      -- $$ proc=mem_dat $$	
62	  );
63	end entity;
64	
65	------------------------------------------------------------------------------
66	-- Architecture Declaration
67	------------------------------------------------------------------------------
68	architecture rtl of psi_ms_daq_daq_dma is
69	
70	  -- Constants
71	  constant BufferFifoDepth_c : integer := 32;
72	
73	  -- Number of bits to encode stream is at least 1 (otherwise the special case for one stream would require separate code).
74	  -- .. The overhead generated by this is regarded as aceptable (better wasting a few LUTs than much development time)
75	  constant StreamBits_c : integer := max(log2ceil(Streams_g), 1);
76	  constant IntDataBytes_c : positive := IntDataWidth_g/8;
77	  constant BytesWidth_c   : positive := log2ceil(IntDataBytes_c);
78	
79	  -- Component Connection Signals
80	  signal CmdFifo_Level_Dbg : std_logic_vector(StreamBits_c downto 0);
81	  signal CmdFifo_InData    : std_logic_vector(DaqSm2DaqDma_Cmd_Size_c - 1 downto 0);
82	  signal CmdFifo_OutData   : std_logic_vector(DaqSm2DaqDma_Cmd_Size_c - 1 downto 0);
83	  signal CmdFifo_Cmd       : DaqSm2DaqDma_Cmd_t;
84	  signal CmdFifo_Vld       : std_logic;
85	  signal RspFifo_Level_Dbg : std_logic_vector(StreamBits_c downto 0);
86	  signal RspFifo_InData    : std_logic_vector(DaqDma2DaqSm_Resp_Size_c - 1 downto 0);
87	  signal RspFifo_OutData   : std_logic_vector(DaqDma2DaqSm_Resp_Size_c - 1 downto 0);
88	  signal DatFifo_Level_Dbg : std_logic_vector(log2ceil(BufferFifoDepth_c) downto 0);
89	  signal DatFifo_AlmFull   : std_logic;
90	  signal Rem_RdBytes       : std_logic_vector(BytesWidth_c - 1 downto 0);
91	  signal Rem_Data          : std_logic_vector(IntDataWidth_g - 1 downto 0);
92	  signal Rem_Trigger       : std_logic;
93	  signal Rem_Last          : std_logic;
94	  signal Rem_Data_Fifo_In  : std_logic_vector(BytesWidth_c + IntDataWidth_g + 1 downto 0);
95	  signal Rem_Data_Fifo_Out : std_logic_vector(BytesWidth_c + IntDataWidth_g + 1 downto 0);
96	
97	  -- Types
98	  type State_t is (Idle_s, RemRd1_s, RemRd2_s, Transfer_s, Done_s, Cmd_s);
99	
100	  -- Two process method
101	  type two_process_r is record
102	    CmdFifo_Rdy  : std_logic;
103	    RspFifo_Vld  : std_logic;
104	    RspFifo_Data : DaqDma2DaqSm_Resp_t;
105	    Mem_DataVld  : std_logic;
106	    StreamStdlv  : std_logic_vector(StreamBits_c - 1 downto 0);
107	    RemWen       : std_logic;
108	    RemWrBytes   : std_logic_vector(BytesWidth_c - 1 downto 0);
109	    RemData      : std_logic_vector(IntDataWidth_g - 1 downto 0);
110	    RemTrigger   : std_logic;
111	    RemLast      : std_logic;
112	    RemWrTrigger : std_logic;
113	    RemWrLast    : std_logic;
114	    State        : State_t;
115	    HndlMaxSize  : unsigned(15 downto 0);
116	    RdBytes      : unsigned(15 downto 0);
117	    WrBytes      : unsigned(15 downto 0);
118	    HndlStream   : integer range 0 to MaxStreams_c - 1;
119	    HndlAddress  : std_logic_vector(31 downto 0);
120	    UpdateLast   : std_logic;
121	    HndlSft      : unsigned(BytesWidth_c-1 downto 0);
122	    FirstDma     : std_logic_vector(Streams_g - 1 downto 0);
123	    Mem_CmdVld   : std_logic;
124	    Trigger      : std_logic;
125	    Last         : std_logic;
126	    DataSft      : std_logic_vector(2*IntDataWidth_g - 1 downto 0);
127	    NextDone     : std_logic;
128	    DataWritten  : std_logic;
129	    HasLast      : std_logic_vector(Streams_g - 1 downto 0);
130	  end record;
131	  signal r, r_next : two_process_r;
132	
133	begin
134	  --------------------------------------------
135	  -- Combinatorial Process
136	  --------------------------------------------
137	  p_comb : process(r, DaqSm_Cmd, DaqSm_Cmd_Vld, DaqSm_Resp_Rdy, Inp_Vld, Inp_Data, Mem_CmdRdy, Mem_DatRdy, CmdFifo_Cmd, CmdFifo_Vld, DatFifo_AlmFull, Rem_RdBytes, Rem_Data, Rem_Trigger, Rem_Last)
138	    variable v          : two_process_r;
139	    variable ThisByte_v : std_logic_vector(7 downto 0);
140	    variable RemSft_v   : integer range 0 to 7;
141	  begin
142	    -- *** Hold variables stable ***
143	    v := r;
144	
145	    -- *** Default Values ***
146	    v.CmdFifo_Rdy := '0';
147	    Inp_Rdy       <= (others => '0');
148	    v.Mem_DataVld := '0';
149	    v.RspFifo_Vld := '0';
150	    v.RemWen      := '0';
151	    v.UpdateLast  := '0';
152	
153	    -- *** State Machine ***
154	    case r.State is
155	
156	      when Idle_s =>
157	        v.HndlMaxSize := unsigned(CmdFifo_Cmd.MaxSize);
158	        v.HndlStream  := CmdFifo_Cmd.Stream;
159	        v.StreamStdlv := std_logic_vector(to_unsigned(CmdFifo_Cmd.Stream, v.StreamStdlv'length));
160	        v.HndlAddress := CmdFifo_Cmd.Address;
161	        v.Trigger     := '0';
162	        v.Last        := '0';
163	        if CmdFifo_Vld = '1' then
164	          v.CmdFifo_Rdy := '1';
165	          v.State       := RemRd1_s;
166	        end if;
167	
168	      when RemRd1_s =>
169	        v.State := RemRd2_s;
170	
171	      when RemRd2_s =>
172	        -- Prevent RAM data from before reset to have an influence
173	        v.WrBytes                := (others => '0');
174	        if r.FirstDma(r.HndlStream) = '1' then
175	          v.HndlSft    := (others => '0');
176	          v.RdBytes    := (others => '0');
177	          v.DataSft    := (others => '0');
178	          v.RemTrigger := '0';
179	          v.RemLast    := '0';
180	        else
181	          v.HndlSft                := unsigned(Rem_RdBytes);
182	          v.DataSft(2*IntDataWidth_g - 1 downto IntDataWidth_g) := Rem_Data;
183	          v.RdBytes                := resize(unsigned(Rem_RdBytes), v.RdBytes'length);
184	          v.RemTrigger             := Rem_Trigger;
185	          v.RemLast                := Rem_Last;
186	        end if;
187	        v.FirstDma(r.HndlStream) := '0';
188	        v.State                  := Transfer_s;
189	        v.NextDone               := '0';
190	        v.DataWritten            := '0';
191	
192	      when Transfer_s =>
193	        -- TF done because of maximum size reached
194	        if r.WrBytes >= r.HndlMaxSize then
195	          v.State := Done_s;
196	        elsif DatFifo_AlmFull = '0' then
197	          if r.NextDone = '0' and Inp_Vld(r.HndlStream) = '1' and r.RemLast = '0' then
198	            v.RdBytes := r.RdBytes + unsigned(Inp_Data(r.HndlStream).Bytes);
199	          end if;
200	          v.WrBytes := r.WrBytes + IntDataBytes_c;
201	          -- Combinatorial handling because of fall-through interface at input
202	          if r.RdBytes < r.HndlMaxSize and r.NextDone = '0' and r.RemLast = '0' then
203	            Inp_Rdy(r.HndlStream) <= '1';
204	          end if;
205	          -- Handling of last frame
206	          if (Inp_Data(r.HndlStream).Last = '1') or (r.RemLast = '1') then
207	            -- Do one more word if not all data can be transferred in the current beat (NextDone = 1)
208	            if (r.HndlSft + unsigned(Inp_Data(r.HndlStream).Bytes) <= IntDataBytes_c) or (r.RemLast = '1') then
209	              v.State := Done_s;
210	            else
211	              v.NextDone := '1';
212	            end if;
213	            if (Inp_Data(r.HndlStream).IsTrig = '1') or (r.RemTrigger = '1') then
214	              v.Trigger := '1';
215	            end if;
216	            v.Last := '1';
217	          end if;
218	          if r.NextDone = '1' or Inp_Vld(r.HndlStream) = '0' then
219	            v.State := Done_s;
220	          end if;
221	          -- Data handling
222	          v.DataSft(IntDataWidth_g - 1 downto 0)                                                     := r.DataSft(2*IntDataWidth_g - 1 downto IntDataWidth_g);
223	          v.DataSft(8 * to_integer(r.HndlSft) + IntDataWidth_g - 1 downto 8 * to_integer(r.HndlSft)) := Inp_Data(r.HndlStream).Data;
224	          if Inp_Vld(r.HndlStream) = '1' or r.HndlSft /= 0 then
225	            v.Mem_DataVld := '1';
226	            v.DataWritten := '1';
227	          end if;
228	        end if;
229	
230	      when Done_s =>
231	        RemSft_v       := to_integer(resize(r.HndlMaxSize, 3));
232	        v.RemWrTrigger := '0';
233	        v.RemWrLast    := '0';
234	        if r.HndlMaxSize < r.RdBytes then
235	          v.RemWrBytes            := std_logic_vector(resize(r.RdBytes - r.HndlMaxSize, v.RemWrBytes'length));
236	          v.RdBytes               := r.HndlMaxSize;
237	          v.RemWrTrigger          := r.Trigger;
238	          v.RemWrLast             := r.Last;
239	          v.HasLast(r.HndlStream) := r.Last;
240	        else
241	          v.RemWrBytes            := (others => '0');
242	          v.HasLast(r.HndlStream) := '0';
243	        end if;
244	        v.RemData      := v.DataSft(8 * RemSft_v + IntDataWidth_g - 1 downto 8 * RemSft_v);
245	        v.State        := Cmd_s;
246	        if r.DataWritten = '1' then
247	          v.Mem_CmdVld := '1';
248	        end if;
249	        v.RemWen       := '1';
250	
251	      when Cmd_s =>
252	        if Mem_CmdRdy = '1' or r.Mem_CmdVld = '0' then
253	          v.State               := Idle_s;
254	          v.Mem_CmdVld          := '0';
255	          v.RspFifo_Vld         := '1';
256	          v.RspFifo_Data.Size   := std_logic_vector(r.RdBytes);
257	          -- Only mark as trigger if all samples are completely written to memory (no remaining samples in REM RAM)
258	          if (unsigned(r.RemWrBytes) = 0) and (r.Trigger = '1') then
259	            v.RspFifo_Data.Trigger := '1';
260	          else
261	            v.RspFifo_Data.Trigger := '0';
262	          end if;
263	          v.RspFifo_Data.Stream := r.HndlStream;
264	        end if;
265	      when others => null;
266	    end case;
267	
268	    -- *** Assign to signal ***
269	    r_next <= v;
270	
271	  end process;
272	
273	  -- *** Registered Outputs ***
274	  Mem_CmdAddr                                             <= r.HndlAddress;
275	  Mem_CmdSize(r.RdBytes'range)                            <= std_logic_vector(r.RdBytes);
276	  Mem_CmdSize(Mem_CmdSize'high downto r.RdBytes'high + 1) <= (others => '0');
277	  Mem_CmdVld                                              <= r.Mem_CmdVld;
278	  DaqSm_HasLast                                           <= r.HasLast;
279	
280	  --------------------------------------------
281	  -- Sequential Process
282	  --------------------------------------------
283	  p_seq : process(Clk)
284	  begin
285	    if rising_edge(Clk) then
286	      r <= r_next;
287	      if Rst = '1' then
288	        r.CmdFifo_Rdy <= '0';
289	        r.RspFifo_Vld <= '0';
290	        r.Mem_DataVld <= '0';
291	        r.RemWen      <= '0';
292	        r.State       <= Idle_s;
293	        r.FirstDma    <= (others => '1');
294	        r.Mem_CmdVld  <= '0';
295	        r.HasLast     <= (others => '0');
296	      end if;
297	    end if;
298	  end process;
299	
300	  --------------------------------------------
301	  -- Component Instantiation
302	  --------------------------------------------
303	  -- *** Command FIFO ***
304	  CmdFifo_InData <= DaqSm2DaqDma_Cmd_ToStdlv(DaqSm_Cmd);
305	  i_fifocmd : entity work.psi_common_sync_fifo
306	    generic map(
307	      width_g        => DaqSm2DaqDma_Cmd_Size_c,
308	      depth_g        => 2**StreamBits_c,
309	      ram_style_g    => "distributed",
310	      ram_behavior_g => "RBW"
311	    )
312	    port map(
313	      clk_i       => Clk,
314	      rst_i       => Rst,
315	      dat_i       => CmdFifo_InData,
316	      vld_i       => DaqSm_Cmd_Vld,
317	      dat_o       => CmdFifo_OutData,
318	      vld_o       => CmdFifo_Vld,
319	      rdy_i       => r.CmdFifo_Rdy,
320	      out_level_o => CmdFifo_Level_Dbg
321	    );
322	  CmdFifo_Cmd    <= DaqSm2DaqDma_Cmd_FromStdlv(CmdFifo_OutData);
323	
324	  -- *** Response FIFO ***
325	  -- Ready not required for system reasons: There is never more commands open than streams.
326	  RspFifo_InData <= DaqDma2DaqSm_Resp_ToStdlv(r.RspFifo_Data);
327	  i_fiforsp : entity work.psi_common_sync_fifo
328	    generic map(
329	      width_g        => DaqDma2DaqSm_Resp_Size_c,
330	      depth_g        => 2**StreamBits_c,
331	      ram_style_g    => "distributed",
332	      ram_behavior_g => "RBW"
333	    )
334	    port map(
335	      clk_i       => Clk,
336	      rst_i       => Rst,
337	      dat_i       => RspFifo_InData,
338	      vld_i       => r.RspFifo_Vld,
339	      dat_o       => RspFifo_OutData,
340	      vld_o       => DaqSm_Resp_Vld,
341	      rdy_i       => DaqSm_Resp_Rdy,
342	      out_level_o => RspFifo_Level_Dbg
343	    );
344	  DaqSm_Resp     <= DaqDme2DaqSm_Resp_FromStdlv(RspFifo_OutData);
345	
346	  -- *** Buffer FIFO ***
347	  -- This FIFO allows buffering data for the time the state machine requires to react on a "memory interface not ready for more data" situation.
348	  -- As a result, the backpressure must not handled in the complete pipeline of this block.
349	  -- Rdy is not required since the data pipeline is stopped based on the almost full flag
350	  i_fifodata : entity work.psi_common_sync_fifo
351	    generic map(
352	      width_g          => IntDataWidth_g,
353	      depth_g          => BufferFifoDepth_c,
354	      alm_full_on_g    => true,
355	      alm_full_level_g => BufferFifoDepth_c / 2,
356	      ram_style_g      => "distributed",
357	      ram_behavior_g   => "RBW"
358	    )
359	    port map(
360	      clk_i       => Clk,
361	      rst_i       => Rst,
362	      dat_i       => r.DataSft(IntDataWidth_g-1 downto 0),
363	      vld_i       => r.Mem_DataVld,
364	      dat_o       => Mem_DatData,
365	      vld_o       => Mem_DatVld,
366	      rdy_i       => Mem_DatRdy,
367	      out_level_o => DatFifo_Level_Dbg,
368	      alm_full_o  => DatFifo_AlmFull
369	    );
370	
371	  -- *** Remaining Data RAM ***
372	  Rem_Data_Fifo_In(BytesWidth_c + IntDataWidth_g + 1)                       <= r.RemWrLast;
373	  Rem_Data_Fifo_In(BytesWidth_c + IntDataWidth_g)                           <= r.RemWrTrigger;
374	  Rem_Data_Fifo_In(BytesWidth_c + IntDataWidth_g - 1 downto IntDataWidth_g) <= r.RemWrBytes;
375	  Rem_Data_Fifo_In(IntDataWidth_g - 1 downto 0)                             <= r.RemData;
376	
377	  i_remram : entity work.psi_common_sdp_ram
378	    generic map(
379	      depth_g        => 2**StreamBits_c,
380	      width_g        => 1 + 1 + BytesWidth_c + IntDataWidth_g,
381	      is_async_g     => false,
382	      ram_style_g    => "distributed",
383	      ram_behavior_g => "RBW"
384	    )
385	    port map(
386	      wr_clk_i               => Clk,
387	      rd_clk_i               => Rst,
388	      wr_addr_i              => r.StreamStdlv,
389	      wr_i                   => r.RemWen,
390	      wr_dat_i               => Rem_Data_Fifo_In,
391	      rd_addr_i              => r.StreamStdlv,
392	      rd_dat_o               => Rem_Data_Fifo_Out
393	    );
394	
395	    Rem_Last    <= Rem_Data_Fifo_Out(BytesWidth_c + IntDataWidth_g + 1);
396	    Rem_Trigger <= Rem_Data_Fifo_Out(BytesWidth_c + IntDataWidth_g);
397	    Rem_RdBytes <= Rem_Data_Fifo_Out(BytesWidth_c + IntDataWidth_g - 1 downto IntDataWidth_g);
398	    Rem_Data    <= Rem_Data_Fifo_Out(IntDataWidth_g - 1 downto 0);
399	
400	end;
401

