6	
7	------------------------------------------------------------------------------
8	-- Libraries
9	------------------------------------------------------------------------------
10	library ieee;
11	use ieee.std_logic_1164.all;
12	use ieee.numeric_std.all;
13	
14	library work;
15	use work.psi_common_math_pkg.all;
16	
17	------------------------------------------------------------------------------
18	-- Entity Declaration
19	------------------------------------------------------------------------------
20	entity psi_ms_daq_axi_if is
21	  generic(
22	    IntDataWidth_g          : positive                 := 64;
23	    AxiDataWidth_g          : natural range 64 to 1024 := 64;
24	    AxiMaxBeats_g           : natural range 1 to 256   := 256;
25	    AxiMaxOpenTrasactions_g : natural range 1 to 8     := 8;
26	    MaxOpenCommands_g       : positive                 := 16;
27	    DataFifoDepth_g         : natural                  := 1024;
28	    AxiFifoDepth_g          : natural                  := 1024;
29	    RamBehavior_g           : string                   := "RBW"
30	  );
31	  port(
32	    -- Control Signals
33	    Clk           : in  std_logic;
34	    Rst_n         : in  std_logic;
35	    -- Write Command
36	    Cmd_Addr      : in  std_logic_vector(31 downto 0);
37	    Cmd_Size      : in  std_logic_vector(31 downto 0);
38	    Cmd_Vld       : in  std_logic;
39	    Cmd_Rdy       : out std_logic;
40	    -- Write Data
41	    Dat_Data      : in  std_logic_vector(IntDataWidth_g - 1 downto 0);
42	    Dat_Vld       : in  std_logic;
43	    Dat_Rdy       : out std_logic;
44	    -- Response
45	    Done          : out std_logic;
46	    -- AXI Address Write Channel
47	    M_Axi_AwAddr  : out std_logic_vector(31 downto 0);
48	    M_Axi_AwLen   : out std_logic_vector(7 downto 0);
49	    M_Axi_AwSize  : out std_logic_vector(2 downto 0);
50	    M_Axi_AwBurst : out std_logic_vector(1 downto 0);
51	    M_Axi_AwLock  : out std_logic;
52	    M_Axi_AwCache : out std_logic_vector(3 downto 0);
53	    M_Axi_AwProt  : out std_logic_vector(2 downto 0);
54	    M_Axi_AwValid : out std_logic;
55	    M_Axi_AwReady : in  std_logic                                     := '0';
56	    -- AXI Write Data Channel                                                           					
57	    M_Axi_WData   : out std_logic_vector(AxiDataWidth_g - 1 downto 0);
58	    M_Axi_WStrb   : out std_logic_vector(AxiDataWidth_g / 8 - 1 downto 0);
59	    M_Axi_WLast   : out std_logic;
60	    M_Axi_WValid  : out std_logic;
61	    M_Axi_WReady  : in  std_logic                                     := '0';
62	    -- AXI Write Response Channel                                                      
63	    M_Axi_BResp   : in  std_logic_vector(1 downto 0)                  := (others => '0');
64	    M_Axi_BValid  : in  std_logic                                     := '0';
65	    M_Axi_BReady  : out std_logic;
66	    -- AXI Read Address Channel                                               
67	    M_Axi_ArAddr  : out std_logic_vector(31 downto 0);
68	    M_Axi_ArLen   : out std_logic_vector(7 downto 0);
69	    M_Axi_ArSize  : out std_logic_vector(2 downto 0);
70	    M_Axi_ArBurst : out std_logic_vector(1 downto 0);
71	    M_Axi_ArLock  : out std_logic;
72	    M_Axi_ArCache : out std_logic_vector(3 downto 0);
73	    M_Axi_ArProt  : out std_logic_vector(2 downto 0);
74	    M_Axi_ArValid : out std_logic;
75	    M_Axi_ArReady : in  std_logic                                     := '0';
76	    -- AXI Read Data Channel                                                      
77	    M_Axi_RData   : in  std_logic_vector(AxiDataWidth_g - 1 downto 0) := (others => '0');
78	    M_Axi_RResp   : in  std_logic_vector(1 downto 0)                  := (others => '0');
79	    M_Axi_RLast   : in  std_logic                                     := '0';
80	    M_Axi_RValid  : in  std_logic                                     := '0';
81	    M_Axi_RReady  : out std_logic
82	  );
83	end entity;
84	
85	------------------------------------------------------------------------------
86	-- Architecture Declaration
87	------------------------------------------------------------------------------
88	architecture rtl of psi_ms_daq_axi_if is
89	  signal Rst : std_logic;
90	
91	  subtype CommandAddrRng_c is natural range 31 downto 0;
92	  subtype CommandSizeRng_c is natural range 63 downto 32;
93	  constant WrCmdWidth_c : integer := CommandSizeRng_c'high + 1;
94	  signal InfoFifoIn     : std_logic_vector(WrCmdWidth_c - 1 downto 0);
95	  signal InfoFifoOut    : std_logic_vector(WrCmdWidth_c - 1 downto 0);
96	  signal WrCmdFifo_Vld  : std_logic;
97	  signal WrCmdFifo_Rdy  : std_logic;
98	  signal WrCmdFifo_Addr : std_logic_vector(31 downto 0);
99	  signal WrCmdFifo_Size : std_logic_vector(31 downto 0);
100	  signal DoneI          : std_logic;
101	  signal ErrorI         : std_logic;
102	
103	begin
104	  Rst <= not Rst_n;
105	
106	  InfoFifoIn(CommandAddrRng_c) <= Cmd_Addr;
107	  InfoFifoIn(CommandSizeRng_c) <= Cmd_Size;
108	
109	  i_wrinfo_fifo : entity work.psi_common_sync_fifo
110	    generic map(
111	      width_g     => WrCmdWidth_c,
112	      depth_g     => MaxOpenCommands_g,
113	      ram_style_g => "distributed"
114	    )
115	    port map(
116	      clk_i => Clk,
117	      rst_i => Rst,
118	      dat_i => InfoFifoIn,
119	      vld_i => Cmd_Vld,
120	      rdy_o => Cmd_Rdy,
121	      dat_o => InfoFifoOut,
122	      vld_o => WrCmdFifo_Vld,
123	      rdy_i => WrCmdFifo_Rdy
124	    );
125	
126	  WrCmdFifo_Addr <= InfoFifoOut(CommandAddrRng_c);
127	  WrCmdFifo_Size <= InfoFifoOut(CommandSizeRng_c);
128	
129	  i_axi : entity work.psi_common_axi_master_full
130	    generic map(
131	      axi_addr_width_g             => 32,
132	      axi_data_width_g             => AxiDataWidth_g,
