99	uint32_t Log2(const uint32_t x)
100	{
101		uint32_t v = x;
102		uint32_t r = 0;
103		while (v > 1) {
104			v = v/2;
105			r = r+1;
106		}
107		return r;
108	}
109	
110	uint32_t Log2Ceil(const uint32_t x)
111	{
112		if (0 == x) {
113			return 0;
114		}
115		return Log2(x);
116	}
117	
118	uint32_t Pow(const uint32_t x, const uint32_t y)
119	{
120		uint32_t r = x;
121		for (uint32_t i = 1; i < y; i ++) {
122			r *= x;
123		}
124		return r;
125	}
