129	//*******************************************************************************
130	// IP Wide Functions
131	//*******************************************************************************
132	PsiMsDaq_IpHandle PsiMsDaq_Init(	const uint32_t baseAddr,
133										const uint8_t maxStreams,
134										const uint8_t maxWindows,
135										const PsiMsDaq_AccessFct_t* const accessFct_p)
136	{
137		//Initialization and allocation
138		PsiMsDaq_Inst_t* inst_p = (PsiMsDaq_Inst_t*) malloc(sizeof(PsiMsDaq_Inst_t));
139		inst_p->baseAddr = baseAddr;
140		inst_p->streams = (PsiMsDaq_StrInst_t*) malloc(sizeof(PsiMsDaq_StrInst_t)*maxStreams);
141		inst_p->maxWindows = maxWindows;
142		inst_p->maxStreams = maxStreams;
143		inst_p->strAddrOffs = Pow(2, Log2Ceil(maxWindows))*0x10;
144		//Standard access functions
145		if (NULL == accessFct_p) {
146			inst_p->memcpyFct = PsiMsDaq_DataCopy_Standard;
147			inst_p->regWrFct = PsiMsDaq_RegWrite_Standard;
148			inst_p->regRdFct = PsiMsDaq_RegRead_Standard;
149		}
150		else {
151			inst_p->memcpyFct = accessFct_p->dataCopy;
152			inst_p->regWrFct = accessFct_p->regWrite;
153			inst_p->regRdFct = accessFct_p->regRead;
154		}
155		//Disable complete IP (all streams, IRQs, etc.)
156		PsiMsDaq_RegWrite(inst_p, PSI_MS_DAQ_REG_GCFG, 0);
157		PsiMsDaq_RegWrite(inst_p, PSI_MS_DAQ_REG_STRENA, 0);
158		PsiMsDaq_RegWrite(inst_p, PSI_MS_DAQ_REG_IRQENA, 0);
159		PsiMsDaq_RegWrite(inst_p, PSI_MS_DAQ_REG_IRQVEC, 0xFFFFFFFF);
160		//Reset values for all streams
161		for (int str = 0; str < maxStreams; str++) {
162			//Clear stream maximum level
163			PsiMsDaq_RegWrite(inst_p, PSI_MS_DAQ_REG_MAXLVL(str), 0);
164			//Mark windows as free
165			for (int win = 0; win < maxWindows; win++) {
166				PsiMsDaq_RegWrite(inst_p, PSI_MS_DAQ_WIN_WINCNT(str, win, inst_p->strAddrOffs), 0);
167			}
168			//Initialize data structure
169			inst_p->streams[str].nr = str;
170			inst_p->streams[str].isConfigured = false;
171			inst_p->streams[str].irqFctWin = NULL;
172			inst_p->streams[str].irqFctStr = NULL;
173			inst_p->streams[str].irqArg = NULL;
174			inst_p->streams[str].ipHandle = (PsiMsDaq_IpHandle) inst_p;
175			inst_p->streams[str].lastProcWin = -1;
176			inst_p->streams[str].irqCalledWin = 0;
177		}
178		//Set general Enables (never touched later)
179		PsiMsDaq_RegWrite(inst_p, PSI_MS_DAQ_REG_GCFG, PSI_MS_DAQ_REG_GCFG_BIT_ENA | PSI_MS_DAQ_REG_GCFG_BIT_IRQENA);
180		return (PsiMsDaq_IpHandle) inst_p;
