//*******************************************************************************
// Macros
//*******************************************************************************
#define SAFE_CALL(fctCall) { \
		PsiMsDaq_RetCode_t r = fctCall; \
		if (PsiMsDaq_RetCode_Success != r) {return r;}}

//*******************************************************************************
// Private Functions
