	inst_p->regWrFct(inst_p->baseAddr+addr, value);
	//Done
	return PsiMsDaq_RetCode_Success;
}

PsiMsDaq_RetCode_t PsiMsDaq_RegRead(	PsiMsDaq_IpHandle ipHandle,
										const uint32_t addr,
